python3 -c "
import json
keywords = ['Chelsea', 'Maresca', 'Man United', 'Iran', 'AFCON', 'Grammy', 'Oscar', 'NFL', 'Super Bowl', 'Broncos', 'Patriots', 'Seahawks', 'Australian Open', 'tennis', 'Champions League', 'Syria', 'Ukraine', 'Greenland', 'TikTok', 'Venezuela']
with open('articles/2025/12/26/articles.jsonl') as f:
    articles = [json.loads(line) for line in f]
print(f'Total articles: {len(articles)}')
for kw in keywords:
    count = 0
    titles = []
    for i, a in enumerate(articles):
        title = a.get('title', '') or ''
        if kw.lower() in title.lower():
            count += 1
            if len(titles) < 2:
                titles.append(f'  {title[:120]}')
    if count > 0:
        print(f'\\n--- {kw} ({count} titles) ---')
        for t in titles:
            print(t)
"
